import React from 'react';

const mockPickups = [
  { time: '10:00 AM', customer: 'Rahul Sharma', orderId: 'ORD-1001', items: 5, status: 'Ready' },
  { time: '11:30 AM', customer: 'Priya Mehta', orderId: 'ORD-1006', items: 3, status: 'Ready' },
  { time: '02:00 PM', customer: 'Neha Kapoor', orderId: 'ORD-1004', items: 2, status: 'Ready' },
  { time: '04:30 PM', customer: 'Arjun Verma', orderId: 'ORD-1007', items: 4, status: 'In Cleaning' },
];

const UpcomingPickups: React.FC = () => {
  return (
    <div className="card" style={{ flex: 1 }}>
      <div className="card-header">
        <div className="card-title">Upcoming Pickups</div>
        <a href="#" className="card-action">View calendar</a>
      </div>

      <div className="pickup-list">
        {mockPickups.map((pickup, idx) => (
          <div className="pickup-item" key={idx}>
            <div className="pickup-time">{pickup.time}</div>
            <div className="pickup-details">
              <div className="pickup-name">{pickup.customer}</div>
              <div className="pickup-sub">{pickup.orderId} • {pickup.items} items</div>
            </div>
            <div className="pickup-status">
              <span className={`status-badge ${pickup.status === 'Ready' ? 'ready' : 'in_cleaning'}`}>
                {pickup.status}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default UpcomingPickups;
